'use client';
import Link from 'next/link';
import { useEffect, useRef } from 'react';

const LOGO_SRC = "data:image/png;base64,";
const MOCKUP_SRC = "data:image/jpeg;base64,";

export default function LandingPage() {
  const heroRef = useRef<HTMLElement>(null);

  useEffect(() => {
    // Snowflakes
    const hero = heroRef.current;
    if (!hero) return;
    const flakes: HTMLSpanElement[] = [];
    for (let i = 0; i < 22; i++) {
      const s = document.createElement('span');
      s.className = 'piq-sf';
      s.textContent = ['❄','❅','❆'][i % 3];
      s.style.cssText = `left:${Math.random()*100}%;top:${Math.random()*-60-10}px;font-size:${9+Math.random()*10}px;animation-duration:${7+Math.random()*9}s;animation-delay:${Math.random()*6}s;opacity:${0.15+Math.random()*0.45}`;
      hero.appendChild(s);
      flakes.push(s);
    }
    // Scroll reveal
    const els = document.querySelectorAll('.piq-reveal');
    const ro = new IntersectionObserver((entries) => {
      entries.forEach((e, idx) => {
        if (e.isIntersecting) {
          (e.target as HTMLElement).style.transitionDelay = `${idx * 0.04}s`;
          e.target.classList.add('piq-visible');
        }
      });
    }, { threshold: 0.08 });
    els.forEach(el => ro.observe(el));
    return () => {
      flakes.forEach(s => s.remove());
      ro.disconnect();
    };
  }, []);

  return (
    <>
      <style>{`
        .piq-sf {
          position:absolute; color:rgba(255,255,255,0.35); pointer-events:none;
          animation:piqSnow linear infinite; font-size:14px; z-index:1;
        }
        @keyframes piqSnow {
          0%   { opacity:0; transform:translateY(-20px) rotate(0deg) }
          5%   { opacity:0.7 }
          95%  { opacity:0.3 }
          100% { opacity:0; transform:translateY(100vh) rotate(720deg) translateX(20px) }
        }
        @keyframes piqFloat  { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-12px)} }
        @keyframes piqFadeUp { from{opacity:0;transform:translateY(22px)} to{opacity:1;transform:translateY(0)} }
        @keyframes piqPulse  { 0%,100%{box-shadow:0 0 0 0 rgba(22,163,74,.5)} 50%{box-shadow:0 0 0 8px rgba(22,163,74,0)} }
        .piq-reveal { opacity:0; transform:translateY(22px); transition:opacity .6s ease, transform .6s ease }
        .piq-visible { opacity:1 !important; transform:none !important }
        .piq-live-dot {
          display:inline-block; width:6px; height:6px; background:#16a34a;
          border-radius:50%; animation:piqPulse 2s infinite; margin-right:5px;
        }
        .piq-score-bar { transition: width 1.2s cubic-bezier(0.16,1,0.3,1) }
      `}</style>

      {/* ── NAV ── */}
      <nav style={{
        position:'fixed', top:0, left:0, right:0, zIndex:200, height:'62px',
        display:'flex', alignItems:'center', padding:'0 28px',
        justifyContent:'space-between',
        background:'rgba(13,27,78,0.97)', backdropFilter:'blur(20px)',
        borderBottom:'1px solid rgba(255,255,255,0.07)'
      }}>
        <div style={{display:'flex', alignItems:'center', gap:'32px'}}>
          <Link href="/" style={{display:'flex', alignItems:'center', gap:'8px', textDecoration:'none'}}>
            <img src={LOGO_SRC} alt="PowderIQ" style={{width:'36px', height:'36px', objectFit:'contain'}} />
            <span style={{fontSize:'19px', fontWeight:800, color:'#fff', letterSpacing:'-0.02em', fontFamily:'inherit'}}>PowderIQ</span>
          </Link>
          <div style={{display:'flex', gap:'2px'}} className="piq-nav-links">
            {([["Mountains","/mountains"],["Features","#features"],["Pricing","#pricing"],["For Resorts","#resort-ops"]] as [string,string][]).map(([label,href]) => (
              <Link key={label} href={href} style={{
                fontSize:'14px', fontWeight:500, color:'rgba(255,255,255,0.6)',
                padding:'7px 14px', borderRadius:'8px', textDecoration:'none',
                transition:'all 0.18s'
              }}
              onMouseEnter={e=>{(e.target as HTMLElement).style.cssText+='color:#fff;background:rgba(255,255,255,0.08)'}}
              onMouseLeave={e=>{(e.target as HTMLElement).style.color='rgba(255,255,255,0.6)';(e.target as HTMLElement).style.background='transparent'}}
              >{label}</Link>
            ))}
          </div>
        </div>
        <div style={{display:'flex', gap:'8px', alignItems:'center'}}>
          <Link href="/auth/login" style={{
            fontSize:'14px', fontWeight:500, color:'rgba(255,255,255,0.75)',
            padding:'8px 16px', borderRadius:'9px', textDecoration:'none',
            border:'1px solid rgba(255,255,255,0.15)', transition:'all 0.18s'
          }}>Sign In</Link>
          <Link href="/auth/signup" style={{
            fontSize:'14px', fontWeight:700, color:'#fff',
            padding:'8px 18px', borderRadius:'9px', textDecoration:'none',
            background:'#1565d8', boxShadow:'0 2px 12px rgba(21,101,216,0.4)',
            transition:'all 0.18s'
          }}>Get Started Free</Link>
        </div>
      </nav>

      {/* ── HERO ── */}
      <section ref={heroRef} id="hero" style={{
        minHeight:'100vh', paddingTop:'62px', position:'relative', overflow:'hidden',
        display:'flex', alignItems:'center',
        background:'linear-gradient(150deg,#0b1a42 0%,#0d2158 45%,#112970 80%,#0b1f55 100%)'
      }}>
        {/* mesh glow */}
        <div style={{
          position:'absolute', inset:0, pointerEvents:'none',
          background:'radial-gradient(ellipse 70% 60% at 75% 40%,rgba(21,101,216,0.28) 0%,transparent 70%),radial-gradient(ellipse 50% 50% at 20% 80%,rgba(6,182,212,0.15) 0%,transparent 65%)'
        }}/>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px', position:'relative', zIndex:2, width:'100%'}}>
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:'48px', alignItems:'center', padding:'80px 0 60px'}}>
            {/* LEFT */}
            <div>
              <div style={{
                display:'inline-flex', alignItems:'center', gap:'7px',
                background:'rgba(6,182,212,0.12)', border:'1px solid rgba(6,182,212,0.3)',
                color:'#67e8f9', fontSize:'12px', fontWeight:700,
                letterSpacing:'0.07em', textTransform:'uppercase',
                padding:'5px 13px', borderRadius:'100px', marginBottom:'22px',
                animation:'piqFadeUp 0.5s ease both'
              }}>❄ Real-time snow intelligence</div>
              <h1 style={{
                fontSize:'clamp(38px,4.8vw,64px)', fontWeight:800, lineHeight:1.04,
                color:'#fff', letterSpacing:'-0.035em', marginBottom:'20px',
                animation:'piqFadeUp 0.6s 0.08s ease both'
              }}>
                Know Before<br/>You <span style={{color:'#67e8f9'}}>Drop In</span>
              </h1>
              <p style={{
                fontSize:'18px', lineHeight:1.65, color:'rgba(255,255,255,0.6)',
                maxWidth:'460px', marginBottom:'36px',
                animation:'piqFadeUp 0.6s 0.16s ease both'
              }}>
                PowderIQ scores every resort daily using real weather data — blending Open-Meteo, OpenWeather, and NOAA — so you always chase the right mountain.
              </p>
              <div style={{display:'flex', gap:'12px', flexWrap:'wrap', marginBottom:'44px', animation:'piqFadeUp 0.6s 0.22s ease both'}}>
                <Link href="/auth/signup" style={{
                  display:'inline-flex', alignItems:'center', gap:'8px',
                  padding:'14px 26px', borderRadius:'12px',
                  background:'#1565d8', color:'#fff',
                  fontWeight:700, fontSize:'15px', textDecoration:'none',
                  boxShadow:'0 4px 22px rgba(21,101,216,0.5)'
                }}>🎿 Start Free — No Card Needed</Link>
                <Link href="/mountains" style={{
                  display:'inline-flex', alignItems:'center', gap:'8px',
                  padding:'14px 26px', borderRadius:'12px',
                  background:'rgba(255,255,255,0.08)', color:'#fff',
                  fontWeight:600, fontSize:'15px', textDecoration:'none',
                  border:'1px solid rgba(255,255,255,0.18)'
                }}>Browse 370+ Mountains →</Link>
              </div>
              <div style={{display:'flex', gap:'30px', animation:'piqFadeUp 0.6s 0.3s ease both'}}>
                {([["370+","Resorts tracked"],["3x","Weather sources"],["30m","Data refresh"]] as [string,string][]).map(([num,lbl]) => (
                  <div key={lbl}>
                    <div style={{fontSize:'30px', fontWeight:800, color:'#fff', letterSpacing:'-0.02em', lineHeight:1}}>
                      {num.replace(/[+xm]/,'')}
                      <span style={{color:'#67e8f9'}}>{num.match(/[+xm]/)?.[0]}</span>
                    </div>
                    <div style={{fontSize:'12px', color:'rgba(255,255,255,0.45)', marginTop:'4px'}}>{lbl}</div>
                  </div>
                ))}
              </div>
            </div>
            {/* RIGHT — app mockup */}
            <div style={{position:'relative', display:'flex', justifyContent:'center', animation:'piqFadeUp 0.7s 0.1s ease both'}}>
              {/* floating score card */}
              <div style={{
                position:'absolute', top:'6%', left:'-10%', zIndex:10,
                background:'#fff', borderRadius:'14px',
                boxShadow:'0 16px 60px rgba(13,27,78,0.22)',
                border:'1px solid rgba(21,101,216,0.18)',
                padding:'14px 16px', minWidth:'200px',
                animation:'piqFloat 5s 0.5s ease-in-out infinite'
              }}>
                <div style={{fontSize:'10px', fontWeight:700, color:'#7b93c8', textTransform:'uppercase', letterSpacing:'0.07em', marginBottom:'8px'}}>
                  <span className="piq-live-dot"/>Top Powder Today
                </div>
                {([["Kirkwood Mtn","California · 14\" new","88","#dcfce7","#15803d"],["Sugar Bowl","California · 7\" new","79","#dbeafe","#1d4ed8"]] as [string,string,string,string,string][]).map(([name,sub,score,bg,fg]) => (
                  <div key={name} style={{display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px', marginBottom:'6px'}}>
                    <div>
                      <div style={{fontSize:'12px', fontWeight:700, color:'#0d1f4e'}}>{name}</div>
                      <div style={{fontSize:'10px', color:'#7b93c8'}}>📍 {sub}</div>
                    </div>
                    <span style={{fontSize:'14px', fontWeight:800, padding:'3px 8px', borderRadius:'7px', background:bg, color:fg, fontFamily:'monospace'}}>{score}</span>
                  </div>
                ))}
                <div style={{display:'flex', gap:'6px', marginTop:'10px'}}>
                  {([["Summit","26°F"],["Mid","30°F"],["Base","34°F"]] as [string,string][]).map(([zone,temp]) => (
                    <div key={zone} style={{flex:1, background:'#0d1f4e', borderRadius:'7px', padding:'7px 5px', textAlign:'center'}}>
                      <div style={{fontSize:'8px', color:'rgba(255,255,255,0.4)', textTransform:'uppercase'}}>{zone}</div>
                      <div style={{fontSize:'13px', fontWeight:700, color:'#fff', fontFamily:'monospace'}}>{temp}</div>
                    </div>
                  ))}
                </div>
              </div>
              <img src={MOCKUP_SRC} alt="PowderIQ app screens" style={{
                width:'100%', maxWidth:'540px', borderRadius:'16px',
                boxShadow:'0 32px 100px rgba(0,0,0,0.4)',
                animation:'piqFloat 7s ease-in-out infinite', marginTop:'60px'
              }}/>
              {/* floating alert */}
              <div style={{
                position:'absolute', bottom:'8%', right:'-8%', zIndex:10,
                background:'#fff', borderRadius:'14px',
                boxShadow:'0 16px 60px rgba(13,27,78,0.22)',
                border:'1px solid rgba(21,101,216,0.18)',
                padding:'14px 16px', minWidth:'180px',
                animation:'piqFloat 6s 1s ease-in-out infinite'
              }}>
                <div style={{fontSize:'10px', fontWeight:700, color:'#7b93c8', textTransform:'uppercase', letterSpacing:'0.07em', marginBottom:'8px'}}>❄️ Powder Alert</div>
                <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px'}}>
                  <div>
                    <div style={{fontSize:'12px', fontWeight:700, color:'#0d1f4e'}}>Crystal Mountain</div>
                    <div style={{fontSize:'10px', color:'#7b93c8'}}>Score hit 74 · 6" overnight</div>
                  </div>
                  <span style={{fontSize:'14px', fontWeight:800, padding:'3px 8px', borderRadius:'7px', background:'#dbeafe', color:'#1d4ed8', fontFamily:'monospace'}}>74</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── MOUNTAINS ── */}
      <section style={{background:'#f7f9ff', padding:'88px 0'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div style={{display:'grid', gridTemplateColumns:'1.1fr 0.9fr', gap:'48px', alignItems:'start'}}>
            <div>
              <div className="piq-reveal" style={{marginBottom:'48px'}}>
                <div style={{display:'inline-flex', alignItems:'center', gap:'7px', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', color:'#1565d8'}}>Live Rankings</div>
                <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#0d1f4e', letterSpacing:'-0.025em', lineHeight:1.1, marginBottom:'12px'}}>Top Powder Today</h2>
                <p style={{fontSize:'16px', color:'#3d5694', lineHeight:1.65, maxWidth:'540px'}}>Updated every 30 minutes from real weather data. No guessing, no marketing fluff.</p>
              </div>
              <div style={{display:'flex', flexDirection:'column', gap:'10px'}}>
                {([
                  ["#1","🏔️","Kirkwood Mountain","California · 7,800 ft · 14\" fresh","14\"","26°","88","great"],
                  ["#2","⛷️","Sugar Bowl","California · 6,883 ft · 7\" fresh","7\"","27°","79","great"],
                  ["#3","🎿","Crystal Mountain","Washington · 4,400 ft · 6\" fresh","6\"","28°","74","good"],
                  ["#4","🏂","Stevens Pass","Washington · 4,061 ft · 2\" fresh","2\"","31°","61","good"],
                  ["#5","⛰️","Mt. Bachelor","Oregon · 5,663 ft · 0\" fresh","0\"","29°","42","fair"],
                ] as [string,string,string,string,string,string,string,string][]).map(([rank,icon,name,meta,snow,temp,score,tier]) => {
                  const bg = tier==='great'?'#dcfce7':tier==='good'?'#dbeafe':'#fef3c7';
                  const fg = tier==='great'?'#15803d':tier==='good'?'#1d4ed8':'#92400e';
                  return (
                    <Link key={name} href="/mountains" className="piq-reveal" style={{
                      background:'#fff', borderRadius:'16px', padding:'16px 18px',
                      border:'1px solid rgba(21,101,216,0.10)',
                      display:'flex', alignItems:'center', gap:'14px',
                      textDecoration:'none', transition:'all 0.25s',
                      boxShadow:'0 1px 4px rgba(13,27,78,0.06)'
                    }}>
                      <span style={{fontSize:'11px', fontWeight:800, color:'#7b93c8', fontFamily:'monospace', minWidth:'20px'}}>{rank}</span>
                      <div style={{width:'44px', height:'44px', borderRadius:'10px', flexShrink:0, background:'linear-gradient(135deg,#0d1f4e,#1d3a8a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px'}}>{icon}</div>
                      <div style={{flex:1, minWidth:0}}>
                        <div style={{fontSize:'14px', fontWeight:700, color:'#0d1f4e'}}>{name}</div>
                        <div style={{fontSize:'11px', color:'#7b93c8', marginTop:'2px'}}>{meta}</div>
                      </div>
                      <div style={{display:'flex', gap:'10px', alignItems:'center'}}>
                        <div style={{textAlign:'right'}}><div style={{fontSize:'12px', fontWeight:700, color:'#0d1f4e', fontFamily:'monospace'}}>{snow}</div><div style={{fontSize:'9px', color:'#7b93c8', textTransform:'uppercase', letterSpacing:'0.06em'}}>24h</div></div>
                        <div style={{textAlign:'right'}}><div style={{fontSize:'12px', fontWeight:700, color:'#0d1f4e', fontFamily:'monospace'}}>{temp}</div><div style={{fontSize:'9px', color:'#7b93c8', textTransform:'uppercase', letterSpacing:'0.06em'}}>Summit</div></div>
                      </div>
                      <span style={{fontSize:'16px', fontWeight:800, fontFamily:'monospace', padding:'5px 10px', borderRadius:'9px', background:bg, color:fg, minWidth:'46px', textAlign:'center'}}>{score}</span>
                    </Link>
                  );
                })}
              </div>
              <Link href="/mountains" className="piq-reveal" style={{
                display:'flex', alignItems:'center', justifyContent:'center', gap:'8px',
                marginTop:'14px', padding:'13px', borderRadius:'11px',
                background:'#1565d8', color:'#fff', fontWeight:700, fontSize:'14px',
                textDecoration:'none'
              }}>View All 370+ Mountains →</Link>
            </div>
            {/* Sticky panel */}
            <div className="piq-reveal" style={{
              background:'#0d1f4e', borderRadius:'20px', overflow:'hidden',
              boxShadow:'0 32px 100px rgba(13,27,78,0.3)', position:'sticky', top:'80px'
            }}>
              <div style={{padding:'20px 22px 16px', borderBottom:'1px solid rgba(255,255,255,0.08)', display:'flex', alignItems:'center', justifyContent:'space-between'}}>
                <span style={{fontSize:'15px', fontWeight:700, color:'#fff'}}>Kirkwood Mountain</span>
                <span style={{fontSize:'11px', color:'#16a34a', fontWeight:700, display:'flex', alignItems:'center'}}><span className="piq-live-dot"/>Live</span>
              </div>
              <div style={{padding:'18px 22px'}}>
                <div style={{fontSize:'12px', color:'rgba(255,255,255,0.4)', marginBottom:'16px'}}>📍 El Dorado County, CA · 9,010 ft summit</div>
                <div style={{display:'flex', alignItems:'baseline', gap:'12px', marginBottom:'10px'}}>
                  <div style={{fontSize:'64px', fontWeight:800, color:'#fff', fontFamily:'monospace', lineHeight:1}}>88</div>
                  <div><div style={{fontSize:'20px', fontWeight:700, color:'#67e8f9', lineHeight:1.2}}>Epic</div><div style={{fontSize:'12px', color:'rgba(255,255,255,0.4)'}}>Updated 4 min ago</div></div>
                </div>
                <div style={{height:'6px', background:'rgba(255,255,255,0.1)', borderRadius:'3px', marginBottom:'20px', overflow:'hidden'}}>
                  <div className="piq-score-bar" style={{height:'100%', borderRadius:'3px', background:'linear-gradient(90deg,#3b82f6,#67e8f9)', width:'88%'}}/>
                </div>
                <div style={{display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'8px', marginBottom:'16px'}}>
                  {([["Summit","26°F","8 mph","14\" new"],["Mid","29°F","5 mph","12\" new"],["Base","33°F","3 mph","9\" new"]] as [string,string,string,string][]).map(([zone,temp,wind,snow]) => (
                    <div key={zone} style={{background:'rgba(255,255,255,0.05)', border:'1px solid rgba(255,255,255,0.07)', borderRadius:'10px', padding:'12px 10px', textAlign:'center'}}>
                      <div style={{fontSize:'9px', color:'rgba(255,255,255,0.4)', textTransform:'uppercase', letterSpacing:'0.07em', marginBottom:'4px'}}>{zone}</div>
                      <div style={{fontSize:'18px', fontWeight:700, color:'#fff', fontFamily:'monospace'}}>{temp}</div>
                      <div style={{fontSize:'10px', color:'#67e8f9', marginTop:'2px'}}>{wind}</div>
                      <div style={{fontSize:'10px', color:'#93c5fd'}}>{snow}</div>
                    </div>
                  ))}
                </div>
              </div>
              <div style={{padding:'14px 22px 18px', display:'flex', gap:'12px', borderTop:'1px solid rgba(255,255,255,0.06)'}}>
                {([["27\"","7-Day Total"],["84\"","Base Depth"],["14/15","Lifts Open"],["Great","Grooming"]] as [string,string][]).map(([val,lbl]) => (
                  <div key={lbl} style={{flex:1, textAlign:'center'}}>
                    <div style={{fontSize:'16px', fontWeight:700, color: lbl==='Grooming'?'#4ade80':'#fff', fontFamily:'monospace'}}>{val}</div>
                    <div style={{fontSize:'10px', color:'rgba(255,255,255,0.4)', textTransform:'uppercase', letterSpacing:'0.06em', marginTop:'2px'}}>{lbl}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── FEATURES ── */}
      <section id="features" style={{background:'#fff', padding:'88px 0'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div className="piq-reveal" style={{textAlign:'center', marginBottom:'48px'}}>
            <div style={{display:'inline-flex', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', color:'#1565d8'}}>How It Works</div>
            <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#0d1f4e', letterSpacing:'-0.025em', lineHeight:1.1, marginBottom:'12px'}}>Snow intelligence, finally done right</h2>
            <p style={{fontSize:'16px', color:'#3d5694', lineHeight:1.65, maxWidth:'540px', margin:'0 auto'}}>Three real-time weather APIs, blended per elevation zone, scored by six weighted factors. Updated every 30 minutes.</p>
          </div>
          <div style={{display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'20px'}}>
            {([
              ["🌨️","Blended Weather Sources","Open-Meteo for snow accumulation, OpenWeather for current conditions, NOAA for official snowpack — merged per elevation zone."],
              ["📊","Powder Score (0–100)","Six weighted factors: 24h snowfall, 7-day base, snow depth, wind, temp stability, and crowd. Updated every 30 minutes."],
              ["🗺️","Official Trail Maps","Beautiful illustrated trail maps from skimap.org's 27,000+ archive. Most recent map with live lift status overlaid."],
              ["⭐","Personalized Scoring","Powder hunter, freestyle, or beginner — your rider profile shifts the scoring weights to match what matters to you."],
              ["🔔","Powder Alerts","Set a target score for any mountain. Get notified the moment conditions cross your threshold."],
              ["⚖️","Resort Compare","Side-by-side across snow, wind, temp, base depth, and crowd. Pick the better day with confidence."],
            ] as [string,string,string][]).map(([icon,title,body]) => (
              <div key={title} className="piq-reveal" style={{
                background:'#f7f9ff', border:'1px solid rgba(21,101,216,0.10)',
                borderRadius:'16px', padding:'28px 24px', transition:'all 0.28s'
              }}>
                <div style={{width:'46px', height:'46px', borderRadius:'12px', marginBottom:'18px', background:'linear-gradient(135deg,#0d1f4e,#1d3a8a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'21px'}}>{icon}</div>
                <div style={{fontSize:'16px', fontWeight:700, color:'#0d1f4e', marginBottom:'8px'}}>{title}</div>
                <div style={{fontSize:'14px', color:'#3d5694', lineHeight:1.65}}>{body}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── TRAIL MAPS ── */}
      <section style={{background:'linear-gradient(150deg,#0b1c46 0%,#0f2560 50%,#0c1e52 100%)', padding:'88px 0', overflow:'hidden', position:'relative'}}>
        <div style={{position:'absolute', inset:0, background:'radial-gradient(ellipse 60% 80% at 80% 50%,rgba(21,101,216,0.22) 0%,transparent 65%)', pointerEvents:'none'}}/>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px', position:'relative'}}>
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:'56px', alignItems:'center'}}>
            <div className="piq-reveal">
              <div style={{display:'inline-flex', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(255,255,255,0.10)', border:'1px solid rgba(255,255,255,0.2)', color:'rgba(255,255,255,0.8)'}}>Trail Maps</div>
              <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#fff', letterSpacing:'-0.025em', lineHeight:1.1, marginBottom:'12px'}}>Every resort's official map, live</h2>
              <p style={{fontSize:'16px', color:'rgba(255,255,255,0.55)', lineHeight:1.65, maxWidth:'500px', marginBottom:'32px'}}>We pull the latest illustrated trail map from skimap.org then overlay real-time lift and trail status.</p>
              {([["🗺️","Illustrated Resort Maps","Beautiful official trail maps — not satellite imagery — showing the actual terrain layout."],["🟢","Live Lift & Trail Status","Open, closed, wind hold — updated by operators in real time alongside the terrain."],["🌡️","Elevation-Zone Weather","Base, mid, and summit conditions shown in context with the runs."]] as [string,string,string][]).map(([icon,title,body]) => (
                <div key={title} style={{display:'flex', gap:'14px', alignItems:'flex-start', marginBottom:'18px'}}>
                  <div style={{width:'38px', height:'38px', flexShrink:0, borderRadius:'9px', background:'rgba(255,255,255,0.07)', border:'1px solid rgba(255,255,255,0.1)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'17px'}}>{icon}</div>
                  <div><div style={{fontSize:'14px', fontWeight:700, color:'#fff', marginBottom:'4px'}}>{title}</div><div style={{fontSize:'13px', color:'rgba(255,255,255,0.5)', lineHeight:1.55}}>{body}</div></div>
                </div>
              ))}
            </div>
            <div className="piq-reveal" style={{background:'rgba(255,255,255,0.04)', border:'1px solid rgba(255,255,255,0.10)', borderRadius:'20px', overflow:'hidden', boxShadow:'0 40px 100px rgba(0,0,0,0.5)'}}>
              <div style={{background:'rgba(255,255,255,0.07)', padding:'12px 18px', display:'flex', alignItems:'center', justifyContent:'space-between', borderBottom:'1px solid rgba(255,255,255,0.07)'}}>
                <span style={{fontSize:'12px', fontWeight:600, color:'rgba(255,255,255,0.75)'}}><span className="piq-live-dot"/>Pine Knob Ski Resort</span>
                <span style={{fontSize:'11px', color:'rgba(255,255,255,0.35)'}}>Updated 4m ago</span>
              </div>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img src="https://files.skimap.org/gpxcd2eoar3jgudcjdj2cctquuon" alt="Pine Knob trail map" style={{width:'100%', height:'260px', objectFit:'cover', objectPosition:'top', display:'block'}}/>
              <div style={{padding:'14px 18px', display:'flex'}}>
                {([["8","Lifts Open","#4ade80"],["14","Trails Open","#60a5fa"],["38°F","Base Temp","#fff"],["0\"","New Snow","#67e8f9"]] as [string,string,string][]).map(([val,lbl,color]) => (
                  <div key={lbl} style={{flex:1, textAlign:'center', padding:'0 4px', borderLeft: lbl!=='Lifts Open'?'1px solid rgba(255,255,255,0.07)':'none'}}>
                    <div style={{fontSize:'17px', fontWeight:700, color, fontFamily:'monospace'}}>{val}</div>
                    <div style={{fontSize:'9px', color:'rgba(255,255,255,0.4)', textTransform:'uppercase', letterSpacing:'0.07em', marginTop:'2px'}}>{lbl}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── B2B ── */}
      <section id="resort-ops" style={{background:'#f7f9ff', padding:'88px 0'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:'56px', alignItems:'center'}}>
            <div className="piq-reveal">
              <div style={{display:'inline-flex', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', color:'#1565d8'}}>For Resort Operators</div>
              <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#0d1f4e', letterSpacing:'-0.025em', lineHeight:1.1, marginBottom:'12px'}}>Run your mountain smarter</h2>
              <p style={{fontSize:'16px', color:'#3d5694', lineHeight:1.65, maxWidth:'480px', marginBottom:'4px'}}>Give your ops team a live dashboard — update lift status, publish snow reports, upload trail maps, and push guest notifications from one place.</p>
              <div style={{display:'flex', flexDirection:'column', gap:'14px', margin:'24px 0'}}>
                {([["🚡","Live lift & trail status","one click to mark open, closed, or wind hold. Instantly visible to guests."],["📸","Custom map upload","your official trail map becomes the guest-facing view automatically."],["❄️","Morning snow reports","publish base depth, new snow, and surface conditions in seconds."],["🔔","Guest push notifications","alert subscribers when a storm hits or lifts open early."]] as [string,string,string][]).map(([icon,title,body]) => (
                  <div key={title} style={{display:'flex', gap:'12px', alignItems:'flex-start'}}>
                    <div style={{width:'34px', height:'34px', flexShrink:0, borderRadius:'8px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'15px'}}>{icon}</div>
                    <div style={{fontSize:'14px', color:'#3d5694', lineHeight:1.55}}><strong style={{color:'#0d1f4e'}}>{title}</strong> — {body}</div>
                  </div>
                ))}
              </div>
              <Link href="/auth/signup" style={{display:'inline-flex', alignItems:'center', gap:'8px', padding:'13px 24px', borderRadius:'11px', background:'#1565d8', color:'#fff', fontWeight:700, fontSize:'15px', textDecoration:'none', boxShadow:'0 3px 18px rgba(21,101,216,0.4)'}}>Request Resort Demo →</Link>
            </div>
            <div className="piq-reveal" style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:'14px'}}>
              {([["370+","Mountains ready for operator onboarding"],["30m","Weather refresh — always current"],["3x","Weather APIs blended per elevation zone"],["24h","Trail map cache — newest map always shown"]] as [string,string][]).map(([num,lbl]) => (
                <div key={lbl} style={{background:'#fff', border:'1px solid rgba(21,101,216,0.18)', borderRadius:'16px', padding:'22px 18px', boxShadow:'0 2px 10px rgba(13,27,78,0.08)'}}>
                  <div style={{fontSize:'34px', fontWeight:800, color:'#0d1f4e', fontFamily:'monospace', letterSpacing:'-0.02em', lineHeight:1}}>
                    {num.replace(/[+xmh]/,'')}<span style={{color:'#1565d8'}}>{num.match(/[+xmh]/)?.[0]}</span>
                  </div>
                  <div style={{fontSize:'12px', color:'#3d5694', marginTop:'6px', lineHeight:1.5}}>{lbl}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ── PRICING ── */}
      <section id="pricing" style={{background:'#fff', padding:'88px 0'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div className="piq-reveal" style={{textAlign:'center', marginBottom:'48px'}}>
            <div style={{display:'inline-flex', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', color:'#1565d8'}}>Pricing</div>
            <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#0d1f4e', letterSpacing:'-0.025em', marginBottom:'12px'}}>Simple, honest pricing</h2>
            <p style={{fontSize:'16px', color:'#3d5694', maxWidth:'440px', margin:'0 auto'}}>Start free forever. Upgrade when you need more. No contracts.</p>
          </div>
          <div style={{display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'20px', maxWidth:'880px', margin:'0 auto'}}>
            {([
              {plan:"Free",price:"0",featured:false,features:["Scores for all 370+ resorts","Trail maps with live status","3 favorite mountains","30-minute refresh","Basic snow reports"]},
              {plan:"Pro",price:"9",featured:true,features:["Everything in Free","Unlimited favorites","Powder alerts via email","Resort comparison tool","Personalized score weights","7-day snow forecast"]},
              {plan:"Resort Ops",price:"49",featured:false,features:["Everything in Pro","Operator dashboard","Live lift & trail updates","Snow report publishing","Guest push notifications","Custom trail map upload"]},
            ]).map(({plan,price,featured,features}) => (
              <div key={plan} className="piq-reveal" style={{
                background: featured?'#0d1f4e':'#f7f9ff',
                border: `2px solid ${featured?'#1565d8':'rgba(21,101,216,0.10)'}`,
                borderRadius:'20px', padding:'32px 26px', position:'relative',
                transform: featured?'scale(1.03)':'none',
                boxShadow: featured?'0 32px 100px rgba(13,27,78,0.25)':'none'
              }}>
                {featured && <div style={{position:'absolute', top:'-13px', left:'50%', transform:'translateX(-50%)', background:'#1565d8', color:'#fff', fontSize:'11px', fontWeight:800, padding:'3px 14px', borderRadius:'100px', whiteSpace:'nowrap', letterSpacing:'0.06em', textTransform:'uppercase', boxShadow:'0 2px 10px rgba(21,101,216,0.4)'}}>Most Popular</div>}
                <div style={{fontSize:'12px', fontWeight:800, textTransform:'uppercase', letterSpacing:'0.09em', color: featured?'rgba(255,255,255,0.45)':'#7b93c8', marginBottom:'10px'}}>{plan}</div>
                <div style={{fontSize:'40px', fontWeight:800, color: featured?'#fff':'#0d1f4e', letterSpacing:'-0.03em', lineHeight:1}}>
                  <sup style={{fontSize:'20px', fontWeight:600, verticalAlign:'super'}}>$</sup>{price}<sub style={{fontSize:'13px', fontWeight:400, color: featured?'rgba(255,255,255,0.4)':'#7b93c8'}}>/mo</sub>
                </div>
                <div style={{height:'1px', background: featured?'rgba(255,255,255,0.08)':'rgba(21,101,216,0.10)', margin:'22px 0'}}/>
                <ul style={{listStyle:'none', display:'flex', flexDirection:'column', gap:'11px', marginBottom:'26px'}}>
                  {features.map(f => <li key={f} style={{fontSize:'13px', color: featured?'rgba(255,255,255,0.65)':'#3d5694', display:'flex', gap:'7px', alignItems:'flex-start', lineHeight:1.5}}><span style={{color:'#16a34a', fontWeight:800, flexShrink:0}}>✓</span>{f}</li>)}
                </ul>
                <Link href="/auth/signup" style={{
                  display:'block', textAlign:'center', padding:'12px', borderRadius:'10px',
                  fontWeight:700, fontSize:'14px', textDecoration:'none', transition:'all 0.2s',
                  background: featured?'#1565d8':'#e8eef8',
                  color: featured?'#fff':'#0d1f4e',
                  boxShadow: featured?'0 3px 14px rgba(21,101,216,0.4)':'none'
                }}>{featured?'Start Free Trial':plan==='Free'?'Get Started Free':'Start Resort Trial'}</Link>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── TESTIMONIALS ── */}
      <section style={{background:'#f7f9ff', padding:'88px 0'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div className="piq-reveal" style={{textAlign:'center', marginBottom:'48px'}}>
            <div style={{display:'inline-flex', fontSize:'11px', fontWeight:800, letterSpacing:'0.09em', textTransform:'uppercase', padding:'4px 13px', borderRadius:'100px', marginBottom:'14px', background:'rgba(21,101,216,0.10)', border:'1px solid rgba(21,101,216,0.2)', color:'#1565d8'}}>From Skiers</div>
            <h2 style={{fontSize:'clamp(26px,3.5vw,42px)', fontWeight:800, color:'#0d1f4e', letterSpacing:'-0.025em'}}>Powder days don't lie</h2>
          </div>
          <div style={{display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'18px'}}>
            {([
              ["MR","Marcus R.","Powder chaser · Tahoe, CA","Drove four hours to Kirkwood on a score of 88. Got 14 inches of fresh. PowderIQ has never steered me wrong — it's the first app that uses real data instead of resort PR."],
              ["SL","Sarah L.","Intermediate rider · Seattle, WA","Finally a score that accounts for wind. Nothing worse than driving somewhere with fresh snow and finding all upper chairs on hold. PowderIQ flags that upfront."],
              ["JT","Jake T.","Ops Manager · Mountain Resort","We update lift status every morning in 30 seconds. Guests see it instantly on the trail map. Way faster than updating the website manually."],
            ] as [string,string,string,string][]).map(([initials,name,role,quote]) => (
              <div key={name} className="piq-reveal" style={{background:'#fff', borderRadius:'16px', padding:'26px 22px', border:'1px solid rgba(21,101,216,0.10)', boxShadow:'0 1px 4px rgba(13,27,78,0.06)'}}>
                <div style={{color:'#d97706', fontSize:'13px', letterSpacing:'3px', marginBottom:'12px'}}>★★★★★</div>
                <p style={{fontSize:'14px', lineHeight:1.75, color:'#3d5694', marginBottom:'18px', fontStyle:'italic'}}>&ldquo;{quote}&rdquo;</p>
                <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
                  <div style={{width:'36px', height:'36px', borderRadius:'50%', flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', background:'linear-gradient(135deg,#0d1f4e,#3b82f6)', color:'#fff', fontWeight:800, fontSize:'12px'}}>{initials}</div>
                  <div><div style={{fontSize:'13px', fontWeight:700, color:'#0d1f4e'}}>{name}</div><div style={{fontSize:'11px', color:'#7b93c8'}}>{role}</div></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA ── */}
      <section style={{background:'linear-gradient(135deg,#0d1f4e 0%,#1d3a8a 100%)', padding:'90px 0', textAlign:'center', position:'relative', overflow:'hidden'}}>
        <div style={{position:'absolute', top:'50%', left:'50%', transform:'translate(-50%,-50%)', width:'700px', height:'400px', background:'radial-gradient(ellipse,rgba(21,101,216,0.3) 0%,transparent 70%)', pointerEvents:'none'}}/>
        <div className="piq-reveal" style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px', position:'relative'}}>
          <p style={{fontSize:'12px', fontWeight:800, textTransform:'uppercase', letterSpacing:'0.1em', color:'#67e8f9', marginBottom:'14px'}}>Don't miss the next powder day</p>
          <h2 style={{fontSize:'clamp(30px,4.5vw,52px)', fontWeight:800, color:'#fff', letterSpacing:'-0.03em', marginBottom:'16px', lineHeight:1.1}}>Start tracking snow for free</h2>
          <p style={{fontSize:'17px', color:'rgba(255,255,255,0.5)', marginBottom:'32px', maxWidth:'440px', marginLeft:'auto', marginRight:'auto'}}>370+ resorts. Real weather. Honest scores. Updated every 30 minutes.</p>
          <div style={{display:'flex', gap:'12px', justifyContent:'center', flexWrap:'wrap'}}>
            <Link href="/auth/signup" style={{display:'inline-flex', alignItems:'center', gap:'8px', padding:'15px 30px', borderRadius:'11px', background:'#1565d8', color:'#fff', fontWeight:700, fontSize:'16px', textDecoration:'none', boxShadow:'0 4px 22px rgba(21,101,216,0.5)'}}>🎿 Create Free Account</Link>
            <Link href="/mountains" style={{display:'inline-flex', alignItems:'center', gap:'8px', padding:'15px 30px', borderRadius:'11px', background:'#fff', color:'#0d1f4e', fontWeight:700, fontSize:'16px', textDecoration:'none'}}>Browse Mountains</Link>
          </div>
        </div>
      </section>

      {/* ── FOOTER ── */}
      <footer style={{background:'#0d1f4e', padding:'56px 0 28px', borderTop:'1px solid rgba(255,255,255,0.07)'}}>
        <div style={{maxWidth:'1120px', margin:'0 auto', padding:'0 28px'}}>
          <div style={{display:'grid', gridTemplateColumns:'1.4fr 1fr 1fr 1fr', gap:'36px', marginBottom:'44px'}}>
            <div>
              <div style={{display:'flex', alignItems:'center', gap:'9px', marginBottom:'12px'}}>
                <img src={LOGO_SRC} alt="PowderIQ" style={{width:'30px', height:'30px', objectFit:'contain'}}/>
                <span style={{fontSize:'17px', fontWeight:800, color:'#fff'}}>PowderIQ</span>
              </div>
              <p style={{fontSize:'13px', color:'rgba(255,255,255,0.4)', lineHeight:1.65, maxWidth:'240px'}}>Real-time powder scoring and snow intelligence for 370+ mountains. Know before you go.</p>
            </div>
            {([["Product",[["Mountains","/mountains"],["Dashboard","/dashboard"],["Compare Resorts","/compare"],["Powder Alerts","/alerts"]]],["For Resorts",[["Operator Dashboard","/resort/dashboard"],["Pricing","#pricing"],["Request Demo","/auth/signup"]]],["Company",[["About","/about"],["Privacy","/privacy"],["Terms","/terms"],["Contact","mailto:hello@powderiq.com"]]]] as [string,[string,string][][]][]).map(([heading,links]) => (
              <div key={heading}>
                <div style={{fontSize:'12px', fontWeight:800, color:'rgba(255,255,255,0.7)', textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:'14px'}}>{heading}</div>
                <ul style={{listStyle:'none', display:'flex', flexDirection:'column', gap:'9px'}}>
                  {links.map(([label,href]) => <li key={label}><Link href={href} style={{fontSize:'13px', color:'rgba(255,255,255,0.4)', textDecoration:'none'}}>{label}</Link></li>)}
                </ul>
              </div>
            ))}
          </div>
          <div style={{borderTop:'1px solid rgba(255,255,255,0.07)', paddingTop:'22px', display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'8px'}}>
            <p style={{fontSize:'12px', color:'rgba(255,255,255,0.3)'}}>© 2026 PowderIQ · Built by Darkstar Software</p>
            <p style={{fontSize:'12px', color:'rgba(255,255,255,0.3)'}}>Trail maps © <a href="https://skimap.org" style={{color:'rgba(255,255,255,0.4)', textDecoration:'underline'}}>skimap.org</a> · Weather © Open-Meteo, OpenWeather, NOAA</p>
          </div>
        </div>
      </footer>
    </>
  );
}
